3	public actor UsagePoller {
4	    public let connectors: [any UsageConnector]
5	    public let interval: Duration
6	    public let fileManager: UsagesFileManager
7	    private let logger: FileLogger
8	
9	    private var pollingTask: Task<Void, Never>?
10	
11	    public init(
12	        connectors: [any UsageConnector],
13	        interval: Duration = .seconds(180),
14	        fileManager: UsagesFileManager = UsagesFileManager.shared,
15	        logger: FileLogger = Loggers.app
16	    ) {
17	        self.connectors = connectors
18	        self.interval = interval
19	        self.fileManager = fileManager
20	        self.logger = logger
21	    }
22	
23	    public func start() {
24	        guard pollingTask == nil else {
25	            logger.log(.warning, "Poller already running")
26	            return
27	        }
28	        logger.log(.info, "Starting poller with interval \(interval)")
29	        pollingTask = Task {
30	            while !Task.isCancelled {
31	                await self.pollOnce()
32	                try? await Task.sleep(for: self.interval)
33	                guard !Task.isCancelled else { break }
34	            }
35	        }
36	    }
37	
38	    public func stop() {
39	        pollingTask?.cancel()
40	        pollingTask = nil
41	        logger.log(.info, "Poller stopped")
42	    }
43	
44	    public func pollOnce(now: Date = Date()) async {
45	        logger.log(.debug, "Poll tick — fetching from \(connectors.count) connector(s)")
46	
47	        let existingFile = await fileManager.read()
48	        let intervalSeconds = Double(interval.components.seconds)
49	        var skippedCount = 0
50	        let log = self.logger
51	
52	        let entries: [VendorUsageEntry] = await withTaskGroup(of: [VendorUsageEntry].self) { group in
53	            for connector in connectors {
54	                if let account = connector.resolveActiveAccount(),
55	                   let cached = existingFile.usages.first(where: { $0.vendor == connector.vendor && $0.account == account }),
56	                   let acquiredDate = cached.lastAcquiredOn?.date,
57	                   now.timeIntervalSince(acquiredDate) < intervalSeconds {
58	                    let age = Int(now.timeIntervalSince(acquiredDate))
59	                    logger.log(.debug, "Skipping \(connector.vendor)/\(account) — fresh (age \(age)s < \(Int(intervalSeconds))s)")
60	                    skippedCount += 1
61	                    continue
62	                }
63	                group.addTask {
64	                    do {
65	                        return try await connector.fetchUsages()
66	                    } catch {
67	                        log.log(.error, "Connector \(connector.vendor) threw: \(error)")
68	                        return []
69	                    }
70	                }
71	            }
72	            var all: [VendorUsageEntry] = []
73	            for await batch in group {
74	                all.append(contentsOf: batch)
75	            }
76	            return all
77	        }
78	
79	        guard !entries.isEmpty else {
80	            if skippedCount == connectors.count {
81	                logger.log(.debug, "All \(connectors.count) connector(s) up-to-date — skipping file write")
82	            } else {
83	                logger.log(.warning, "No entries returned from any connector")
84	            }
85	            return
86	        }
87	
88	        await fileManager.update(with: entries)
89	        logger.log(.info, "Merged \(entries.count) entry/entries into usages file")
90	    }
91	}
